public net.sourceforge.stripes.action.Resolution updateCartQuantities() {
    javax.servlet.http.HttpServletRequest request = this.context.getRequest();
    java.util.Iterator<org.mybatis.jpetstore.domain.CartItem> cartItems = this.getCart().getAllCartItems();
    while (cartItems.hasNext()) {
        org.mybatis.jpetstore.domain.CartItem cartItem = cartItems.next();
        java.lang.String itemId = cartItem.getItem().getItemId();
        try {
            int quantity = java.lang.Integer.parseInt(request.getParameter(itemId));
            this.getCart().setQuantityByItemId(itemId, quantity);
            if (quantity < 1) {
                cartItems.remove();
            }
        } catch (java.lang.Exception e) {
            // ignore parse exceptions on purpose
        }
    } 
    return new net.sourceforge.stripes.action.ForwardResolution(org.mybatis.jpetstore.web.actions.CartActionBean.VIEW_CART);
}

