    order.getLineItems().forEach((org.mybatis.jpetstore.domain.LineItem lineItem) -> {
        java.lang.String itemId = lineItem.getItemId();
        java.lang.Integer increment = lineItem.getQuantity();
        java.util.Map<java.lang.String, java.lang.Object> param = new java.util.HashMap<java.lang.String, java.lang.Object>(2);
        param.put("itemId", itemId);
        param.put("increment", increment);
        this.itemMapper.updateInventoryQuantity(param);
    });
    this.orderMapper.insertOrder(order);
    this.orderMapper.insertOrderStatus(order);
    order.getLineItems().forEach((org.mybatis.jpetstore.domain.LineItem lineItem) -> {
        lineItem.setOrderId(order.getOrderId());
        this.lineItemMapper.insertLineItem(lineItem);
    });
